-- Martin Fowler (1–18)
(gen_random_uuid(), 'Cualquier tonto puede escribir código que una máquina entiende. Los buenos programadores escriben código que los humanos entienden.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'Refactorizar sin pruebas es como operar sin anestesia: técnicamente posible, pero brutal para todos.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'Un microservicio que hace demasiado ya no es un microservicio: es un monolito disfrazado.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'La base de datos es el corazón del sistema; trátala con el mismo cuidado que tratarías un órgano vital.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'Los límites entre servicios deben reflejar los límites del dominio de negocio, no los límites de los equipos.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'Una API es un contrato. Romperlo sin avisar es traicionar a todos los que confiaron en ti.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'El acoplamiento oculto es el enemigo invisible de los sistemas distribuidos.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'Diseña pensando en el fallo. En producción, todo lo que puede fallar eventualmente fallará.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'La integración continua no es una herramienta: es una disciplina de equipo que exige compromiso diario.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'Un buen esquema de base de datos es documentación ejecutable de las reglas de negocio.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'La consistencia eventual no es un defecto del sistema: es una decisión de diseño consciente con consecuencias reales.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'Versionar una API es admitir que el cambio es inevitable; ignorarlo es pretender que el tiempo no pasa.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'El patrón Strangler Fig te permite matar un monolito sin detener el negocio: migra una pieza a la vez.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'La deuda técnica acumulada en la capa de datos es la más costosa de pagar: los esquemas no mienten.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'Cuando los microservicios se comunican de forma síncrona en cadena, has recreado el monolito con más latencia.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'El evento de dominio es la unidad mínima de verdad en un sistema orientado a eventos.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'Migrar esquemas de base de datos en producción requiere el mismo respeto que una cirugía en un paciente despierto.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'El código limpio no es un lujo: es la única forma sostenible de mantener la velocidad de desarrollo a largo plazo.', 'Martin Fowler', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['discipline','wisdom'], true, 'coding'),

-- Robert C. Martin (19–36)
(gen_random_uuid(), 'Una función debe hacer una sola cosa, hacerla bien y hacerla solamente.', 'Robert C. Martin', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'El principio de responsabilidad única aplicado a servicios: un servicio, una razón para cambiar.', 'Robert C. Martin', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'Abre tu software a la extensión y ciérralo a la modificación; ese es el secreto de la longevidad del código.', 'Robert C. Martin', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'Depende de abstracciones, nunca de implementaciones concretas: esa es la inversión de dependencias.', 'Robert C. Martin', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'El código profesional es aquel que el autor no se avergüenza de mostrar a las tres de la mañana.', 'Robert C. Martin', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'TDD no es escribir pruebas primero: es diseñar el comportamiento antes de implementar la solución.', 'Robert C. Martin', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'Deja el código más limpio de lo que lo encontraste; esa es la regla del boy scout aplicada al software.', 'Robert C. Martin', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'Los nombres importan. Un nombre correcto elimina la necesidad de un comentario explicativo.', 'Robert C. Martin', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'La arquitectura limpia pone las reglas de negocio en el centro y los detalles técnicos en los bordes.', 'Robert C. Martin', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'Un sistema bien diseñado puede cambiar de base de datos sin que el dominio se entere.', 'Robert C. Martin', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'Los comentarios que explican el qué indican que el código no es lo suficientemente claro.', 'Robert C. Martin', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'Las pruebas unitarias son la documentación más honesta que existe: no pueden mentir porque se ejecutan.', 'Robert C. Martin', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'Una buena arquitectura retrasa las decisiones hasta que tienes la información suficiente para tomarlas bien.', 'Robert C. Martin', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'El principio de segregación de interfaces dice: no obligues a nadie a depender de lo que no usa.', 'Robert C. Martin', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'El software que no puede probarse de forma aislada tiene un problema de diseño, no de pruebas.', 'Robert C. Martin', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'La verdadera profesionalidad en software es decir no cuando la solución rápida compromete la integridad del sistema.', 'Robert C. Martin', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'Cada capa de abstracción debe tener una razón de ser clara; las capas sin propósito solo añaden ruido.', 'Robert C. Martin', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'El código es poesía técnica: cada línea innecesaria disminuye la belleza del conjunto.', 'Robert C. Martin', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['discipline','wisdom'], true, 'coding'),

