(gen_random_uuid(), 'El diseño simple no es el más fácil de construir, sino el más difícil de descubrir.', 'Kent Beck', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['wisdom','discipline'], true, 'coding'),
