(gen_random_uuid(), 'El feedback rápido es el motor del aprendizaje; un ciclo de prueba lento es un freno al progreso.', 'Kent Beck', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['discipline','wisdom'], true, 'coding'),
