(gen_random_uuid(), 'La deuda técnica pagada hoy cuesta menos que la misma deuda pagada mañana con intereses.', 'Kent Beck', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['discipline','wisdom'], true, 'coding'),
