(gen_random_uuid(), 'Cuando el código duele al cambiar, te está diciendo que hay un diseño que merece ser descubierto.', 'Kent Beck', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'Un equipo con buenas prácticas de integración convierte los conflictos en conversaciones productivas.', 'Kent Beck', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['discipline','wisdom'], true, 'coding'),

-- Donald Knuth (53–66)
(gen_random_uuid(), 'La optimización prematura es la raíz de todos los males en programación.', 'Donald Knuth', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'Mide antes de optimizar. La intuición sobre rendimiento casi siempre está equivocada.', 'Donald Knuth', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'El arte de programar es el arte de organizar y dominar la complejidad.', 'Donald Knuth', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['wisdom','discipline'], true, 'coding'),
