(gen_random_uuid(), 'Las estructuras de datos son el corazón de los sistemas eficientes; los algoritmos son la sangre.', 'Donald Knuth', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'Comprender profundamente un problema es el noventa por ciento de la solución.', 'Donald Knuth', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['wisdom','discipline'], true, 'coding'),
