(gen_random_uuid(), 'La elegancia en software no es decorativa: es señal de que se entendió el problema correctamente.', 'Donald Knuth', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'Documentar el porqué de una decisión es tan importante como documentar el cómo.', 'Donald Knuth', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'Los números de rendimiento sin contexto de carga son estadísticas sin significado.', 'Donald Knuth', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'La precisión en la especificación de un sistema es la única forma de evitar sorpresas desagradables.', 'Donald Knuth', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'Un programa que funciona por accidente es un programa a punto de fallar por razones desconocidas.', 'Donald Knuth', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'La correctitud debe demostrarse, no suponerse; los sistemas críticos no admiten corazonadas.', 'Donald Knuth', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'Cambiar un sistema sin entenderlo completamente es como operar en la oscuridad con herramientas afiladas.', 'Donald Knuth', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['wisdom','discipline'], true, 'coding'),

-- Edsger Dijkstra (67–80)
(gen_random_uuid(), 'La prueba de programas puede mostrar la presencia de errores, pero nunca su ausencia.', 'Edsger Dijkstra', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'La simplicidad es condición previa para la fiabilidad; los sistemas complejos fallan de formas complejas.', 'Edsger Dijkstra', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'El software que no puede razonarse formalmente no puede confiarse para tareas críticas.', 'Edsger Dijkstra', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'Dominar la complejidad es la esencia de la programación; todo lo demás es detalle técnico.', 'Edsger Dijkstra', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'La depuración es dos veces más difícil que la programación; si escribes código al límite de tu inteligencia, ¿cómo lo depurarás?', 'Edsger Dijkstra', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'Los buenos sistemas son los que fracasan de forma predecible y comprensible.', 'Edsger Dijkstra', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'Un sistema distribuido falla en partes que nadie anticipó; diseña para la sorpresa.', 'Edsger Dijkstra', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'La concurrencia sin disciplina produce errores que solo se manifiestan en producción bajo carga real.', 'Edsger Dijkstra', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'El programador que no puede explicar su código en lenguaje natural no lo entiende del todo.', 'Edsger Dijkstra', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'La separación de responsabilidades no es una recomendación: es la ley fundamental del diseño correcto.', 'Edsger Dijkstra', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'La abstracción correcta oculta la complejidad sin ocultar la información relevante.', 'Edsger Dijkstra', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'Probar con datos reales en producción no es una estrategia de calidad: es una apuesta con usuarios reales.', 'Edsger Dijkstra', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'La corrección de un sistema no puede verificarse mediante la observación externa exclusivamente.', 'Edsger Dijkstra', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'El estado mutable compartido es la fuente de los errores más difíciles de reproducir en sistemas concurrentes.', 'Edsger Dijkstra', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['wisdom','discipline'], true, 'coding'),

-- Brian Kernighan (81–92)
(gen_random_uuid(), 'Depurar es más difícil que programar; si eres tan listo como puedes ser al programar, no serás lo suficientemente listo para depurar.', 'Brian Kernighan', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['wisdom','discipline'], true, 'coding'),
