(gen_random_uuid(), 'El código minimalista no es código perezoso: es código que ha sido pensado profundamente.', 'Brian Kernighan', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'La claridad en los mensajes de error es tan importante como la claridad en el código mismo.', 'Brian Kernighan', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['discipline','wisdom'], true, 'coding'),
(gen_random_uuid(), 'Un sistema de ficheros bien diseñado es una lección de abstracción aplicada al almacenamiento.', 'Brian Kernighan', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['wisdom','discipline'], true, 'coding'),
(gen_random_uuid(), 'La modularidad bien aplicada permite cambiar el interior sin romper el exterior.', 'Brian Kernighan', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['discipline','wisdom'], true, 'coding'),

