(gen_random_uuid(), 'C es un lenguaje que asume que el programador sabe lo que hace; esa libertad tiene un precio en responsabilidad.', 'Dennis Ritchie', 'philosophy', 'es', 'down', 'free', false, 'coding', 'backend', ARRAY['wisdom','discipline'], true, 'coding'),
